# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

package com.example.sharedhandler

import android.app.Activity
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.webkit.URLUtil
import android.widget.Toast

class ShareHandlerActivity : Activity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handleShareIntent(intent)
        finish()
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleShareIntent(intent)
        finish()
    }

    private fun handleShareIntent(intent: Intent?) {
        if (intent == null) return

        when (intent.action) {
            Intent.ACTION_SEND -> handleSend(intent)
            Intent.ACTION_VIEW -> handleView(intent)
        }
    }

    private fun handleSend(intent: Intent) {
        when (intent.type) {
            "text/plain" -> {
                val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)?.trim().orEmpty()
                val sharedTitle = intent.getStringExtra(Intent.EXTRA_SUBJECT)?.trim().orEmpty()
                val url = extractUrl(sharedText)

                if (url != null) {
                    processSharedUrl(url, sharedTitle)
                } else if (sharedText.isNotEmpty()) {
                    processSharedText(sharedText, sharedTitle)
                }
            }

            else -> {
                val sharedUri: Uri? = intent.getParcelableExtra(Intent.EXTRA_STREAM)
                if (sharedUri != null) {
                    processSharedImage(sharedUri)
                }
            }
        }
    }

    private fun handleView(intent: Intent) {
        val data = intent.data
        if (data != null && URLUtil.isNetworkUrl(data.toString())) {
            processSharedUrl(data.toString(), "")
        }
    }

    private fun extractUrl(text: String): String? {
        val trimmed = text.trim()
        return when {
            URLUtil.isHttpsUrl(trimmed) || URLUtil.isHttpUrl(trimmed) -> trimmed
            else -> {
                val regex = Regex("(https?://\\S+)")
                regex.find(trimmed)?.value
            }
        }
    }

    private fun processSharedUrl(url: String, title: String) {
        Toast.makeText(this, "Shared URL: $url", Toast.LENGTH_SHORT).show()
    }

    private fun processSharedText(text: String, title: String) {
        Toast.makeText(this, "Shared Text: $text", Toast.LENGTH_SHORT).show()
    }

    private fun processSharedImage(uri: Uri) {
        contentResolver.takePersistableUriPermission(
            uri,
            Intent.FLAG_GRANT_READ_URI_PERMISSION
        )
        Toast.makeText(this, "Shared Image URI: $uri", Toast.LENGTH_SHORT).show()
    }
}

